"""create canonical Catora domain model

Revision ID: 0002
Revises: 0001
Create Date: 2026-07-21
"""

import base64
import json
import zlib
from collections.abc import Sequence

from alembic import op

revision: str = "0002"
down_revision: str | None = "0001"
branch_labels: str | Sequence[str] | None = None
depends_on: str | Sequence[str] | None = None

_UPGRADE_PAYLOAD = ""
_DOWNGRADE_PAYLOAD = ""


def _statements(payload: str) -> list[str]:
    decoded = zlib.decompress(base64.b64decode(payload))
    value = json.loads(decoded)
    if not isinstance(value, list) or not all(isinstance(item, str) for item in value):
        raise RuntimeError("Invalid embedded migration payload")
    return value


def upgrade() -> None:
    for statement in _statements(_UPGRADE_PAYLOAD):
        op.execute(statement)


def downgrade() -> None:
    for statement in _statements(_DOWNGRADE_PAYLOAD):
        op.execute(statement)
